arguments.new_str:
using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// FIX (Breaking change – ValidateScopes in dev): .NET 9 enables
// ValidateScopes by default in Development. A singleton resolving a scoped
// service from the root provider throws InvalidOperationException. Change the
// lifetime to scoped so it matches its dependency.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX (Breaking change – SocketsHttpHandler default): .NET 9 HttpClientFactory
// uses SocketsHttpHandler instead of HttpClientHandler as the default primary
// handler. The original cast to HttpClientHandler would throw
// InvalidCastException. Use ConfigurePrimaryHttpMessageHandler with the
// correct handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX (Breaking change – header redaction): .NET 9 redacts all header values
// in Trace-level HttpClientFactory logs by default. Allowlist the specific
// non-sensitive headers you need to see.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Accept"
        && h != "Content-Type"));

// FIX (Breaking change – ForwardedHeaders unknown proxies): .NET 9 ignores
// X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
// Add your reverse-proxy address(es) here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1")); // TODO: replace with actual proxy IP
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

